**src/api/routes/user.routes.ts**
```typescript
import { Router, Request, Response, NextFunction } from 'express';
import { UserService } from '../../services/user.service';
import {
  RegisterUserSchema,
  LoginUserSchema,
  UpdateUserSchema,
} from '../../domain/user.dto';
import { validateRequest } from '../middleware/validation.middleware';
import { authMiddleware, AuthRequest } from '../middleware/auth.middleware';
import {
  DuplicateEmailError,
  DuplicateUsernameError,
  InvalidCredentialsError,
  UserNotFoundError,
} from '../../services/user.service';

/**
 * User routes. Thin layer delegating to UserService.
 * No business logic here — only request/response handling.
 */
export function createUserRoutes(userService: UserService): Router {
  const router = Router();

  /**
   * POST /api/users - Register a new user
   */
  router.post(
    '/users',
    validateRequest(RegisterUserSchema),
    async (req: Request, res: Response, next: NextFunction): Promise<void> => {
      try {
        const { user } = req.body;
        const result = await userService.register(user);
        res.status(201).json(result);
      } catch (error) {
        if (
          error instanceof DuplicateEmailError ||
          error instanceof DuplicateUsernameError
        ) {
          res.status(422).json({
            errors: { body: [error.message] },
          });
          return;
        }
        next(error);
      }
    }
  );

  /**
   * POST /api/users/login - Authenticate user
   */
  router.post(
    '/users/login',
    validateRequest(LoginUserSchema),
    async (req: Request, res: Response, next: NextFunction): Promise<void> => {
      try {
        const { user } = req.body;
        const result = await userService.login(user);
        res.status(200).json(result);
      } catch (error) {
        if (error instanceof InvalidCredentialsError) {
          res.status(422).json({
            errors: { body: [error.message] },
          });
          return;
        }
        next(error);
      }
    }
  );

  /**
   * GET /api/user - Get current user (requires auth)
   */
  router.get(
    '/user',
    authMiddleware,
    async (req: AuthRequest, res: Response, next: NextFunction): Promise<void> => {
      try {
        const result = await userService.getCurrentUser(req.userId!);
        res.status(200).json(result);
      } catch (error) {
        if (error instanceof UserNotFoundError) {
          res.status(404).json({
            errors: { body: [error.message] },
          });
          return;
        }
        next(error);
      }
    }
  );

  /**
   * PUT /api/user - Update current user (requires auth)
   */
  router.put(
    '/user',
    authMiddleware,
    validateRequest(UpdateUserSchema),
    async (req: AuthRequest, res: Response, next: NextFunction): Promise<void> => {
      try {
        const { user } = req.body;
        const result = await userService.updateUser(req.userId!, user);
        res.status(200).json(result);
      } catch (error) {
        if (
          error instanceof DuplicateEmailError ||
          error instanceof DuplicateUsernameError
        ) {
          res.status(422).json({
            errors: { body: [error.message] },
          });
          return;
        }
        if (error instanceof UserNotFoundError) {
          res.status(404).json({
            errors: { body: [error.message] },
          });
          return;
        }
        next(error);
      }
    }
  );

  return router;
}
```

### Application Entry Point

**src/index.ts**
```typescript
import express, { Express, Request, Response, NextFunction } from 'express';
import { PrismaClient } from '@prisma/client';
import { PrismaUserRepository } from './repositories/prisma-user.repository';
import { UserService } from './services/user.service';
import { createUserRoutes } from './api/routes/user.routes';

// Environment validation
if (!process.env.JWT_SECRET) {
  throw new Error('JWT_SECRET environment variable is required');
}

if (!process.env.DATABASE_URL) {
  throw new Error('DATABASE_URL environment variable is required');
}

const PORT = process.env.PORT || 3000;

/**
 * Composition root. Wire all dependencies here.
 */
function createApp(): Express {
  const app = express();

  // Middleware
  app.use(express.json());

  // Dependency injection
  const prisma = new PrismaClient();
  const userRepository = new PrismaUserRepository(prisma);
  const userService = new UserService(userRepository);

  // Routes
  app.use('/api', createUserRoutes(userService));

  // Health check
  app.get('/health', (_req: Request, res: Response) => {
    res.status(200).json({ status: 'ok' });
  });

  // Global error handler
  app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
    console.error('Unhandled error:', err);
    res.status(500).json({
      errors: { body: ['Internal server error'] },
    });
  });

  return app;
}

// Start server (only if not in test environment)
if (process.env.NODE_ENV !== 'test') {
  const app = createApp();
  app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
  });
}

export { createApp };
